package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Tests for [CoroutineContext.isActive] extension property.
 */
class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testEmptyContextIsActive() {
        // Empty context (no Job) should be considered active
        assertTrue(EmptyCoroutineContext.isActive)
    }

    @Test
    fun testContextWithActiveJobIsActive() {
        val job = Job()
        val context = EmptyCoroutineContext + job
        assertTrue(context.isActive)
    }

    @Test
    fun testContextWithCancelledJobIsNotActive() {
        val job = Job()
        job.cancel()
        val context = EmptyCoroutineContext + job
        assertFalse(context.isActive)
    }

    @Test
    fun testContextWithCompletedJobIsNotActive() {
        val job = Job()
        job.complete()
        val context = EmptyCoroutineContext + job
        assertFalse(context.isActive)
    }

    @Test
    fun testCoroutineScopeIsActiveConsistency() = runTest {
        // Test that CoroutineContext.isActive is consistent with CoroutineScope.isActive
        // when there is no Job
        val scopeWithoutJob = object : CoroutineScope {
            override val coroutineContext: CoroutineContext = EmptyCoroutineContext
        }

        // Both should return true when no Job is present
        assertEquals(scopeWithoutJob.isActive, scopeWithoutJob.coroutineContext.isActive)
        assertTrue(scopeWithoutJob.isActive)
        assertTrue(scopeWithoutJob.coroutineContext.isActive)
    }

    @Test
    fun testCoroutineContextIsActiveWithJob() = runTest {
        // In a coroutine, coroutineContext.isActive should be true
        assertTrue(coroutineContext.isActive)
    }

    @Test
    fun testCoroutineContextIsActiveAfterCancellation() = runTest {
        val job = Job()
        launch(job) {
            assertTrue(coroutineContext.isActive)
            job.cancel()
            assertFalse(coroutineContext.isActive)
        }.join()
    }
}
"}

